                      color: AppColors.border.withValues(alpha: 0.35)),
                ),
                child: const Text(
                  'Auto mode: Zoom-only (no auto-pan). You can pan freely.',
                  style: TextStyle(fontSize: 12, color: Colors.white70),
                ),
              ),
              const SizedBox(height: AppSpacing.md),
              Row(
                mainAxisAlignment: MainAxisAlignment.spaceBetween,
                children: [
                  Text(l10n?.speedLabel ?? 'Speed',
                      style: AppTypography.labelLarge),
                  Text('${svc.speed.toStringAsFixed(1)}x',
                      style: AppTypography.labelLarge
                          .copyWith(color: AppColors.primary)),
                ],
              ),
              Slider(
                value: svc.speed,
                min: AutoExploreSpeed.min,
                max: AutoExploreSpeed.max,
                divisions: AutoExploreSpeed.sliderDivisions,
                onChanged: (v) {
                  HapticFeedback.selectionClick();
                  svc.speed = v;
                },
              ),
              const SizedBox(height: AppSpacing.md),
              Row(
                children: [
                  Expanded(
                    child: ElevatedButton.icon(
                      onPressed: () =>
                          _runPrimaryAction(status.primaryAction, svc),
                      icon: Icon(status.showsPauseAction
                          ? Icons.pause_rounded
                          : Icons.play_arrow_rounded),
                      label: Text(
                        status.primaryActionLabel(
                          startLabel: l10n?.actionPlay ?? 'Play',
                          pauseLabel: l10n?.actionPause ?? 'Pause',
                          resumeLabel: 'Resume',
                        ),
                      ),
                    ),
                  ),
                  if (svc.isExploring) ...[
                    const SizedBox(width: AppSpacing.md),
                    Expanded(
                      child: OutlinedButton.icon(
                        onPressed: svc.stop,
                        icon: const Icon(Icons.stop_rounded),
                        label: Text(l10n?.actionStop ?? 'Stop'),
                      ),
                    ),
                  ],
                ],
              ),
            ],
          ),
        ),
      ),
    );
  }
}

import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/features/auto_explore/auto_explore_service.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('AutoExploreService', () {
    test('dispose cancels without sending a playback update', () {
      final controller = FractalController(ModuleRegistry());
      final service = AutoExploreService(controller: controller);
      addTearDown(controller.dispose);

      var notifications = 0;
      service.addListener(() => notifications++);

      service.dispose();

      expect(notifications, 0);
    });

    test('ignores one-shot corrections during continuous user interaction',
        () async {
      final controller = FractalController(ModuleRegistry());
      controller.resetView();
      controller.updateZoom(1.0);

      final service = AutoExploreService(
        controller: controller,
        config: const AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1),
        ),
      );
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      service.start();
      await Future<void>.delayed(Duration.zero);
      service.onUserInteractionStart();

      expect(service.pausedByUserCorrection, isTrue);

      controller.updateZoom(2.0);
      service.onUserCorrection();

      expect(service.pausedByUserCorrection, isTrue);
      expect(service.isPaused, isFalse);

      service.onUserInteractionEnd();

      expect(service.pausedByUserCorrection, isFalse);
    });

    test('toggle resumes from temporary user yield instead of pausing',
        () async {
      final controller = FractalController(ModuleRegistry());
      controller.resetView();
      controller.updateZoom(1.0);

      final service = AutoExploreService(
        controller: controller,
        config: const AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1),
        ),
      );
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      service.start();
      await Future<void>.delayed(Duration.zero);
      service.onUserInteractionStart();

      expect(service.pausedByUserCorrection, isTrue);
      expect(service.isPaused, isFalse);

      service.toggle();

      expect(service.isExploring, isTrue);
      expect(service.isPaused, isFalse);
      expect(service.pausedByUserCorrection, isFalse);
    });

    test('resume replans from a zoom changed while paused', () async {
      final controller = FractalController(ModuleRegistry());
      controller.resetView();
      controller.updateZoom(1.0);

      final service = AutoExploreService(
        controller: controller,
        config: const AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1),
        ),
      );
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      service.start();
      await Future<void>.delayed(Duration.zero);
      service.pause();

      controller.updateZoom(10.0);
      service.resume();

      await Future<void>.delayed(Duration.zero);
      await Future<void>.delayed(const Duration(milliseconds: 20));

      expect(controller.view.zoom, 1200.0);
    });

    test('ignores unmatched continuous interaction end callbacks', () async {
      final controller = FractalController(ModuleRegistry());
      controller.resetView();
      controller.updateZoom(1.0);

      final service = AutoExploreService(
        controller: controller,
        config: const AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1),
        ),
      );
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      service.start();
      await Future<void>.delayed(Duration.zero);
      await Future<void>.delayed(const Duration(milliseconds: 20));

      expect(controller.view.zoom, 120.0);

      service.onUserInteractionEnd();
      await Future<void>.delayed(Duration.zero);
      await Future<void>.delayed(const Duration(milliseconds: 20));

      expect(controller.view.zoom, AutoExploreConfig.defaultMinZoom);
    });
  });
}

import 'package:flutter/material.dart';
import 'package:flutter/semantics.dart';
import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/features/auto_explore/auto_explore_controls.dart';
import 'package:flutter_fractals/features/auto_explore/auto_explore_service.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:provider/provider.dart';

void main() {
  group('AutoExploreSettingsSheet', () {
    testWidgets('shows resume affordance while auto-explore is yielded',
        (tester) async {
      final controller = FractalController(ModuleRegistry());
      final service = AutoExploreService(controller: controller);
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      service.start();
      service.onUserInteractionStart();

      await tester.pumpWidget(
        MaterialApp(
          home: ChangeNotifierProvider<AutoExploreService>.value(
            value: service,
            child: const Scaffold(
              body: AutoExploreSettingsSheet(),
            ),
          ),
        ),
      );

      expect(find.text('Auto-pilot paused (user correction)'), findsOneWidget);
      expect(find.text('Resume'), findsOneWidget);
      expect(find.text('Play'), findsNothing);
      expect(find.text('Pause'), findsNothing);
    });
  });

  group('AutoExploreButton semantics', () {
    testWidgets('exposes tap action for assistive activation', (tester) async {
      final semanticsHandle = tester.ensureSemantics();
      final controller = FractalController(ModuleRegistry());
      final service = AutoExploreService(controller: controller);
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      await tester.pumpWidget(
        MaterialApp(
          home: ChangeNotifierProvider<AutoExploreService?>.value(
            value: service,
            child: const Scaffold(
              body: AutoExploreButton(),
            ),
          ),
        ),
      );
      await tester.pumpAndSettle();

      final data = _semanticsDataForLabel(tester, 'Start auto-explore');
      expect(data, isNotNull);
      expect(data!.hasAction(SemanticsAction.tap), isTrue);
      // ignore: deprecated_member_use
      expect(data.hasFlag(SemanticsFlag.isButton), isTrue);

      semanticsHandle.dispose();
    });

    testWidgets('labels user-correction yield without claiming active motion',
        (tester) async {
      final semanticsHandle = tester.ensureSemantics();
      final controller = FractalController(ModuleRegistry());
      final service = AutoExploreService(controller: controller);
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      service.start();
      service.onUserInteractionStart();

      await tester.pumpWidget(
        MaterialApp(
          home: ChangeNotifierProvider<AutoExploreService?>.value(
            value: service,
            child: const Scaffold(
              body: AutoExploreButton(),
            ),
          ),
        ),
      );
      await tester.pumpAndSettle();

      final yieldedData = _semanticsDataForLabel(tester, 'Auto-pilot paused');
      final activeData = _semanticsDataForLabel(tester, 'Pause auto-explore');

      expect(yieldedData, isNotNull);
      expect(yieldedData!.hasAction(SemanticsAction.tap), isTrue);
      expect(activeData, isNull);

      semanticsHandle.dispose();
    });

    testWidgets('tap resumes from user-correction yield instead of pausing',
        (tester) async {
      final controller = FractalController(ModuleRegistry());
      final service = AutoExploreService(controller: controller);
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      service.start();
      service.onUserInteractionStart();

      await tester.pumpWidget(
        MaterialApp(
          home: ChangeNotifierProvider<AutoExploreService?>.value(
            value: service,
            child: const Scaffold(
              body: AutoExploreButton(),
            ),
          ),
        ),
      );
      await tester.pumpAndSettle();

      expect(service.pausedByUserCorrection, isTrue);
      expect(service.isPaused, isFalse);

      await tester.tap(find.byType(AutoExploreButton));
      await tester.pump();

      expect(service.isExploring, isTrue);
      expect(service.isPaused, isFalse);
      expect(service.pausedByUserCorrection, isFalse);

      service.stop();
      await tester.pump();
    });
  });
}

SemanticsData? _semanticsDataForLabel(WidgetTester tester, String label) {
  // ignore: deprecated_member_use
  final root = tester.binding.pipelineOwner.semanticsOwner?.rootSemanticsNode;
  SemanticsData? result;

  bool visit(SemanticsNode node) {
    final data = node.getSemanticsData();
    if (data.label == label) {
      result = data;
      return false;
    }
    node.visitChildren(visit);
    return result == null;
  }

  if (root != null) visit(root);
  return result;
}

