import 'dart:math' as math;

import 'package:vector_math/vector_math.dart' show Vector2;

/// Replayable viewport dimensions for CPU coordinate mapping.
///
/// Render requests should provide positive dimensions. When a direct mapping
/// caller passes invalid dimensions, fall back to a square viewport instead of
/// leaking zero/negative aspect ratios into fractal coordinates.
final class CpuViewportDimensions {
  const CpuViewportDimensions({required this.width, required this.height});

  final int width;
  final int height;

  factory CpuViewportDimensions.fromSize({
    required int width,
    required int height,
  }) {
    if (width <= 0 || height <= 0) {
      return const CpuViewportDimensions(width: 1, height: 1);
    }
    return CpuViewportDimensions(width: width, height: height);
  }

  double get aspect => width / height;
}

/// Replayable CPU viewport center.
///
/// The controller normally provides finite pan coordinates, but CPU fallback
/// code also accepts replayed/isolate scalar requests. Non-finite pan samples
/// must not poison every formula coordinate with NaN/Infinity, so they adopt
/// the origin instead.
final class CpuViewportCenter {
  const CpuViewportCenter({required this.x, required this.y});

  final double x;
  final double y;

  factory CpuViewportCenter.fromScalars({
    required double panX,
    required double panY,
  }) {
    return CpuViewportCenter(
      x: normalizeCoordinate(panX),
      y: normalizeCoordinate(panY),
    );
  }

  static double normalizeCoordinate(double value) {
    return value.isFinite ? value : 0.0;
  }
}

/// Explicit dimensions contract for CPU render work.
final class CpuRenderDimensions {
  const CpuRenderDimensions({required this.width, required this.height});

  final int width;
  final int height;

  void validate() {
    if (width <= 0 || height <= 0) {
      throw ArgumentError.value(
        (width, height),
        'full viewport',
        'must be positive',
      );
    }
  }
}

/// Explicit bounds contract for a CPU render tile inside a full viewport.
final class CpuRenderRect {
  const CpuRenderRect({
    required this.fullWidth,
    required this.fullHeight,
    required this.x0,
    required this.y0,
    required this.w,
    required this.h,
  });

  final int fullWidth;
  final int fullHeight;
  final int x0;
  final int y0;
  final int w;
  final int h;

  void validate() {
    CpuRenderDimensions(width: fullWidth, height: fullHeight).validate();
    if (w <= 0 || h <= 0) {
      throw ArgumentError.value((w, h), 'tile size', 'must be positive');
    }
    if (x0 < 0 || y0 < 0 || x0 + w > fullWidth || y0 + h > fullHeight) {
      throw ArgumentError.value(
        (x0, y0, w, h),
        'tile rect',
        'must be within the full viewport',
      );
    }
  }
}

/// Explicit point contract for a CPU pixel sample inside a full viewport.
final class CpuRenderSamplePoint {
  const CpuRenderSamplePoint({
    required this.fullWidth,
    required this.fullHeight,
    required this.x,
    required this.y,
  });

  final int fullWidth;
  final int fullHeight;
  final int x;
  final int y;

  void validate() {
    CpuRenderDimensions(width: fullWidth, height: fullHeight).validate();
    if (x < 0 || y < 0 || x >= fullWidth || y >= fullHeight) {
      throw ArgumentError.value(
        (x, y),
        'sample coordinate',
        'must be inside the full viewport',
      );
    }
  }
}

/// Shared CPU-render viewport mapping.
///
/// Pixel coordinates are edge-inclusive for iteration buffers, preserving the
/// existing scalar-field/golden contract. Subpixel sample coordinates are
/// center-of-pixel positions and must stay inside the same [-1, 1] viewport.
final class CpuViewportMapping {
  final double centerX;
  final double centerY;
  final double scale;
  final double aspect;

  CpuViewportMapping({
    required Vector2 viewPan,
    required double viewZoom,
    required int width,
    required int height,
  }) : this.fromScalars(
          panX: viewPan.x,
          panY: viewPan.y,
          viewZoom: viewZoom,
          width: width,
          height: height,
        );

  CpuViewportMapping.fromScalars({
    required double panX,
    required double panY,
    required double viewZoom,
    required int width,
    required int height,
  }) : this._(
          center: CpuViewportCenter.fromScalars(panX: panX, panY: panY),
          viewZoom: viewZoom,
          width: width,
          height: height,
        );

  CpuViewportMapping._({
    required CpuViewportCenter center,
    required double viewZoom,
    required int width,
    required int height,
  })  : centerX = center.x,
        centerY = center.y,
        scale = 1.5 / normalizeZoom(viewZoom),
        aspect = CpuViewportDimensions.fromSize(
          width: width,
          height: height,
        ).aspect;

  static double normalizeZoom(double zoom) {
    if (!zoom.isFinite || zoom <= 0.0) return 1.0;
    return zoom;
  }

  double normalizedPixel(int pixel, int extent) {
    if (extent <= 1) return 0.0;
    return (pixel / (extent - 1)) * 2.0 - 1.0;
  }

  double normalizedSample({
    required int pixel,
    required int extent,
    required int sample,
    required int samplesPerAxis,
  }) {
    final safeSamples = samplesPerAxis <= 0 ? 1 : samplesPerAxis;
    final safeSample = sample.clamp(0, safeSamples - 1).toInt();
    return normalizedSampleOffset(
      pixel: pixel,
      extent: extent,
      sampleOffset: (safeSample + 0.5) / safeSamples,
    );
  }

  double normalizedSampleOffset({
    required int pixel,
    required int extent,
    required double sampleOffset,
  }) {
    if (extent <= 1) return 0.0;
    final safePixel = pixel.clamp(0, extent - 1).toInt();
    final safeOffset =
        sampleOffset.isNaN ? 0.5 : sampleOffset.clamp(0.0, 1.0).toDouble();
    final subPixel = safePixel + safeOffset;
    return (subPixel / extent) * 2.0 - 1.0;
  }

  (double x, double y) coordinate({required double nx, required double ny}) {
    return (centerX + nx * scale * aspect, centerY + ny * scale);
  }
}

/// Replayable CPU anti-aliasing grid derived from a requested sample count.
///
/// The CPU renderer samples a square grid, so non-square requests are rounded up
/// to the next square grid instead of silently dropping requested samples.
final class CpuSampleGrid {
  CpuSampleGrid.fromRequestedCount(int requestedCount)
      : this._(
          requestedCount: requestedCount,
          samplesPerAxis: _samplesPerAxisFor(requestedCount),
        );

  const CpuSampleGrid._({
    required this.requestedCount,
    required this.samplesPerAxis,
  });

  final int requestedCount;
  final int samplesPerAxis;

  int get totalSamples => samplesPerAxis * samplesPerAxis;

  bool get wasRoundedUp => totalSamples > math.max(1, requestedCount);

  static int _samplesPerAxisFor(int requestedCount) {
    if (requestedCount <= 0) return 1;
    return math.max(1, math.sqrt(requestedCount).ceil());
  }
}

import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/features/catalog/catalog_entry.dart';
import 'package:flutter_fractals/l10n/app_localizations.dart';

/// Replayable catalog search query used by the catalog screen.
///
/// The UI debounces text input, then filters entries by localized display name,
/// aliases, stable catalog ID, and category. Keeping the case/whitespace
/// normalization in one pure value object makes search behavior testable without
/// pumping the whole catalog widget.
final class CatalogSearchQuery {
  const CatalogSearchQuery._(this.value);

  factory CatalogSearchQuery.fromText(String text) {
    return CatalogSearchQuery._(text.trim().toLowerCase());
  }

  /// Lower-case, trimmed query text.
  final String value;

  bool get isEmpty => value.isEmpty;

  bool matches(CatalogEntry entry, AppLocalizations l10n) {
    if (isEmpty) return true;

    return _searchableFields(entry, l10n).any(
      (field) => field.toLowerCase().contains(value),
    );
  }

  Iterable<String> _searchableFields(
    CatalogEntry entry,
    AppLocalizations l10n,
  ) sync* {
    yield entry.module.displayName(l10n);
    yield* entry.aliases;
    yield entry.catalogId;
    yield entry.category;
  }
}

/// Dimension/category refinement selected in the catalog filter bar.
enum CatalogDimensionFilter { all, twoD, threeD, kaleidoscope }

/// Immutable catalog filter inputs for one replayable filter pass.
final class CatalogFilterCriteria {
  final String query;
  final CatalogDimensionFilter dimensionFilter;
  final String? selectedCategory;

  const CatalogFilterCriteria({
    required this.query,
    this.dimensionFilter = CatalogDimensionFilter.all,
    this.selectedCategory,
  });

  CatalogSearchQuery get searchQuery => CatalogSearchQuery.fromText(query);

  bool get hasActiveRefinements =>
      !searchQuery.isEmpty ||
      dimensionFilter != CatalogDimensionFilter.all ||
      selectedCategory != null;
}

/// Replayable catalog filter outputs consumed by the screen.
///
/// The catalog UI needs three related entry sets from one query snapshot:
/// filtered cards, dimension-chip counts, and category-chip counts. Keeping them
/// together prevents count chips and displayed cards from drifting when a search,
/// dimension, or category refinement is active.
final class CatalogFilterResult {
  final List<CatalogEntry> filteredEntries;
  final List<CatalogEntry> dimensionBaseEntries;
  final List<CatalogEntry> categoryBaseEntries;
  final Map<CatalogDimensionFilter, int> dimensionCounts;
  final Map<String, int> categoryCounts;
  final List<String> sortedCategories;

  const CatalogFilterResult._({
    required this.filteredEntries,
    required this.dimensionBaseEntries,
    required this.categoryBaseEntries,
    required this.dimensionCounts,
    required this.categoryCounts,
    required this.sortedCategories,
  });

  int countForDimension(CatalogDimensionFilter filter) =>
      dimensionCounts[filter] ?? 0;
}

/// Pure catalog filter/count contract shared by UI and tests.
final class CatalogFilter {
  const CatalogFilter._();

  static CatalogFilterResult apply({
    required Iterable<CatalogEntry> entries,
    required CatalogFilterCriteria criteria,
    required AppLocalizations l10n,
  }) {
    final query = criteria.searchQuery;
    final matchesSearch = entries
        .where((entry) => query.matches(entry, l10n))
        .toList(growable: false);

    final dimensionBaseEntries = matchesSearch
        .where(
          (entry) => _matchesSelectedCategory(entry, criteria.selectedCategory),
        )
        .toList(growable: false);
    final dimensionCounts = Map<CatalogDimensionFilter, int>.unmodifiable({
      CatalogDimensionFilter.all: dimensionBaseEntries.length,
      CatalogDimensionFilter.twoD: dimensionBaseEntries
          .where(
            (entry) => matchesDimension(entry, CatalogDimensionFilter.twoD),
          )
          .length,
      CatalogDimensionFilter.threeD: dimensionBaseEntries
          .where(
            (entry) => matchesDimension(entry, CatalogDimensionFilter.threeD),
          )
          .length,
      CatalogDimensionFilter.kaleidoscope: dimensionBaseEntries
          .where(
            (entry) => matchesDimension(
              entry,
              CatalogDimensionFilter.kaleidoscope,
            ),
          )
          .length,
    });

    final categoryBaseEntries = matchesSearch
        .where((entry) => matchesDimension(entry, criteria.dimensionFilter))
        .toList(growable: false);
    final categoryCounts = countCategories(categoryBaseEntries);
    final sortedCategories = sortCategories(
      categoryCounts,
      selectedCategory: criteria.selectedCategory,
    );

    final filteredEntries = categoryBaseEntries
        .where(
          (entry) => _matchesSelectedCategory(entry, criteria.selectedCategory),
        )
        .toList(growable: false);

    return CatalogFilterResult._(
      filteredEntries: filteredEntries,
      dimensionBaseEntries: dimensionBaseEntries,
      categoryBaseEntries: categoryBaseEntries,
      dimensionCounts: dimensionCounts,
      categoryCounts: categoryCounts,
      sortedCategories: sortedCategories,
    );
  }

  static bool matchesDimension(
    CatalogEntry entry,
    CatalogDimensionFilter filter,
  ) {
    switch (filter) {
      case CatalogDimensionFilter.all:
        return true;
      case CatalogDimensionFilter.twoD:
        return entry.module.dimension == FractalDimension.twoD;
      case CatalogDimensionFilter.threeD:
        return entry.module.dimension == FractalDimension.threeD;
      case CatalogDimensionFilter.kaleidoscope:
        return entry.category.toLowerCase().contains('kaleidoscope');
    }
  }

  static Map<String, int> countCategories(Iterable<CatalogEntry> entries) {
    final counts = <String, int>{};
    for (final entry in entries) {
      counts.update(entry.category, (count) => count + 1, ifAbsent: () => 1);
    }
    return Map<String, int>.unmodifiable(counts);
  }

  static List<String> sortCategories(
    Map<String, int> categoryCounts, {
    String? selectedCategory,
  }) {
    final categories = categoryCounts.keys.toList()
      ..sort((a, b) {
        final countCompare = (categoryCounts[b] ?? 0).compareTo(
          categoryCounts[a] ?? 0,
        );
        if (countCompare != 0) return countCompare;
        return a.compareTo(b);
      });

    if (selectedCategory != null && !categories.contains(selectedCategory)) {
      categories.insert(0, selectedCategory);
    }

    return List<String>.unmodifiable(categories);
  }

  static bool _matchesSelectedCategory(
    CatalogEntry entry,
    String? selectedCategory,
  ) {
    return selectedCategory == null || entry.category == selectedCategory;
  }
}

import 'package:flutter_fractals/core/models/fractal_preset.dart';
