import 'package:flutter/widgets.dart';
import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/core/services/test_logger.dart';
import 'package:flutter_fractals/core/services/test_screenshot_service.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';
import 'package:path_provider/path_provider.dart';

enum DebugRunState { idle, running, completed, error }

/// Replayable output-path plan for a debug run.
///
/// The optional constructor `screenshotDir` is a caller override. When omitted
/// or blank, screenshots fall back to the app documents debug directory.
class DebugRunnerOutputPlan {
  final String screenshotDir;

  const DebugRunnerOutputPlan({required this.screenshotDir});

  factory DebugRunnerOutputPlan.fromDocumentsDirectory({
    required String documentsPath,
    String? requestedScreenshotDir,
  }) {
    final override = requestedScreenshotDir?.trim();
    return DebugRunnerOutputPlan(
      screenshotDir: override == null || override.isEmpty
          ? '$documentsPath/debug_screenshots'
          : override,
    );
  }
}

/// Replayable step-count contract for one debug run.
class DebugRunnerStepPlan {
  static const int stepsPerModule = 5;

  final int moduleCount;

  const DebugRunnerStepPlan({required this.moduleCount})
      : assert(moduleCount >= 0, 'moduleCount cannot be negative');

  int get totalSteps => moduleCount * stepsPerModule;
}

class DebugRunnerService extends ChangeNotifier {
  final FractalController controller;
  final ModuleRegistry registry;
  final String? _requestedScreenshotDir;
  final TestLogger _logger = TestLogger();
  late TestScreenshotService _screenshotService;

  DebugRunState _state = DebugRunState.idle;
  int _currentStep = 0;
  int _totalSteps = 0;
  String _statusMessage = '';
  String? _errorMessage;

  DebugRunnerService({
    required this.controller,
    required this.registry,
    String? screenshotDir,
  }) : _requestedScreenshotDir = screenshotDir {
    // The default screenshot dir is resolved once documents storage is known in
    // run(); a provided override can be installed immediately.
    _screenshotService = TestScreenshotService(
      outputDir: screenshotDir ?? '',
    );
  }

  DebugRunState get state => _state;
  int get currentStep => _currentStep;
  int get totalSteps => _totalSteps;
  String get statusMessage => _statusMessage;
  String? get errorMessage => _errorMessage;

  Future<void> run(GlobalKey boundaryKey) async {
    if (_state == DebugRunState.running) return;

    try {
      // Initialize logger
      await _logger.init();

      // Set up screenshot dir.
      final docDir = await getApplicationDocumentsDirectory();
      final outputPlan = DebugRunnerOutputPlan.fromDocumentsDirectory(
        documentsPath: docDir.path,
        requestedScreenshotDir: _requestedScreenshotDir,
      );
      _screenshotService = TestScreenshotService(
        outputDir: outputPlan.screenshotDir,
      );

      final modules = registry.modules;
      final stepPlan = DebugRunnerStepPlan(moduleCount: modules.length);
      _totalSteps = stepPlan.totalSteps;
      _currentStep = 0;
      _state = DebugRunState.running;
      _errorMessage = null;
      notifyListeners();

      _logger.logAction(
        'debugRunner',
        'Debug run started',
        metadata: {'moduleCount': modules.length},
      );

      for (final module in modules) {
        // Step 1: Select module
        _updateStatus('Selecting ${module.id}...');
        controller.selectModule(module);
        await _settle();
        _advanceStep();

        // Step 2: Screenshot default state
        _updateStatus('Capturing ${module.id} default...');
        await _screenshotService.capture(
          boundaryKey,
          '${module.id}_default',
        );
        await _settle();
        _advanceStep();

        // Step 3: Randomize params
        _updateStatus('Randomizing ${module.id}...');
        controller.randomizeParams();
        await _settle();
        _advanceStep();

        // Step 4: Screenshot randomized state
        _updateStatus('Capturing ${module.id} randomized...');
        await _screenshotService.capture(
          boundaryKey,
          '${module.id}_randomized',
        );
        await _settle();
        _advanceStep();

        // Step 5: Reset
        _updateStatus('Resetting ${module.id}...');
        controller.resetSession();
        await _settle();
        _advanceStep();
      }

      _state = DebugRunState.completed;
      _statusMessage = 'Completed! ${modules.length} modules tested.';
      _logger.logAction('debugRunner', 'Debug run completed');
      notifyListeners();
    } catch (e) {
      _state = DebugRunState.error;
      _errorMessage = e.toString();
      _statusMessage = 'Error: $e';
      _logger.logAction('debugRunner', 'Debug run failed: $e');
      notifyListeners();
    }
  }

  void _updateStatus(String message) {
    _statusMessage = message;
    _logger.logAction('debugRunner', message);
    notifyListeners();
  }

  void _advanceStep() {
    _currentStep++;
    notifyListeners();
  }

  /// 500ms settle delay for shader render time
  Future<void> _settle() async {
    await Future.delayed(const Duration(milliseconds: 500));
  }
}

import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/core/services/debug_runner_service.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  TestWidgetsFlutterBinding.ensureInitialized();

  // Helper factories to avoid repeating boilerplate.
  ModuleRegistry makeRegistry() => ModuleRegistry();

  FractalController makeController(ModuleRegistry registry) =>
      FractalController(registry);

  DebugRunnerService makeService({String? screenshotDir}) {
    final registry = makeRegistry();
    final controller = makeController(registry);
    return DebugRunnerService(
      controller: controller,
      registry: registry,
      screenshotDir: screenshotDir,
    );
  }

  // ---------------------------------------------------------------------------
  // Pure debug-run planning helpers
  // ---------------------------------------------------------------------------

  group('DebugRunnerOutputPlan', () {
    test('uses provided screenshot directory instead of document fallback', () {
      final plan = DebugRunnerOutputPlan.fromDocumentsDirectory(
        documentsPath: 'app_docs',
        requestedScreenshotDir: 'custom_shots',
      );

      expect(plan.screenshotDir, 'custom_shots');
    });

    test('falls back to documents debug directory when no override exists', () {
      final plan = DebugRunnerOutputPlan.fromDocumentsDirectory(
        documentsPath: 'app_docs',
      );

      expect(plan.screenshotDir, 'app_docs/debug_screenshots');
    });

    test('treats blank screenshot directory override as missing', () {
      final plan = DebugRunnerOutputPlan.fromDocumentsDirectory(
        documentsPath: 'app_docs',
        requestedScreenshotDir: '   ',
      );

      expect(plan.screenshotDir, 'app_docs/debug_screenshots');
    });
  });

  group('DebugRunnerStepPlan', () {
    test('keeps per-module step count explicit', () {
      const plan = DebugRunnerStepPlan(moduleCount: 3);

      expect(DebugRunnerStepPlan.stepsPerModule, 5);
      expect(plan.totalSteps, 15);
    });
  });

  // ---------------------------------------------------------------------------
  // Construction / initial state
  // ---------------------------------------------------------------------------

  group('DebugRunnerService – construction', () {
    test('initialises with idle state', () {
      final service = makeService();

      expect(service.state, DebugRunState.idle);
    });

    test('initialises currentStep to 0', () {
      final service = makeService();

      expect(service.currentStep, 0);
    });

    test('initialises totalSteps to 0', () {
      final service = makeService();

      expect(service.totalSteps, 0);
    });

    test('initialises statusMessage to empty string', () {
      final service = makeService();

      expect(service.statusMessage, '');
    });

    test('initialises errorMessage to null', () {
      final service = makeService();

      expect(service.errorMessage, isNull);
    });

    test('accepts optional screenshotDir without throwing', () {
      expect(
        () => makeService(screenshotDir: 'custom_shots'),
        returnsNormally,
      );
    });

    test('exposes controller and registry passed at construction', () {
      final registry = makeRegistry();
      final controller = makeController(registry);
      final service = DebugRunnerService(
        controller: controller,
        registry: registry,
      );

      expect(service.controller, same(controller));
      expect(service.registry, same(registry));
    });
  });

  // ---------------------------------------------------------------------------
  // DebugRunState enum
  // ---------------------------------------------------------------------------

  group('DebugRunState enum', () {
    test('has exactly four values', () {
      expect(DebugRunState.values.length, 4);
    });

    test('values are idle, running, completed, error', () {
      expect(DebugRunState.values, contains(DebugRunState.idle));
      expect(DebugRunState.values, contains(DebugRunState.running));
      expect(DebugRunState.values, contains(DebugRunState.completed));
      expect(DebugRunState.values, contains(DebugRunState.error));
    });
  });

  // ---------------------------------------------------------------------------
  // ChangeNotifier – listener registration
  // ---------------------------------------------------------------------------

  group('DebugRunnerService – ChangeNotifier', () {
    test('addListener and removeListener work without errors', () {
      final service = makeService();
      void listener() {}

      service.addListener(listener);
      service.removeListener(listener);

      service.dispose();
    });

    test('dispose does not throw', () {
      final service = makeService();

      expect(() => service.dispose(), returnsNormally);
    });
  });

  // ---------------------------------------------------------------------------
  // FractalController integration (used by DebugRunnerService internally)
  // ---------------------------------------------------------------------------

  group('FractalController – module registry sanity', () {
    test('registry has at least one module', () {
      final registry = makeRegistry();

      expect(registry.modules, isNotEmpty);
    });

    test('first module can be selected on the controller', () {
      final registry = makeRegistry();
      final controller = makeController(registry);

      expect(controller.module, registry.modules.first);
    });

    test('controller can select second module without throwing', () {
      final registry = makeRegistry();
      final controller = makeController(registry);

      if (registry.modules.length >= 2) {
        expect(
          () => controller.selectModule(registry.modules[1]),
          returnsNormally,
        );
      }
    });

    test('controller.randomizeParams does not throw', () {
      final registry = makeRegistry();
      final controller = makeController(registry);

      expect(() => controller.randomizeParams(), returnsNormally);
    });

    test('controller.resetSession does not throw', () {
      final registry = makeRegistry();
      final controller = makeController(registry);

      expect(() => controller.resetSession(), returnsNormally);
    });
  });

  // ---------------------------------------------------------------------------
  // totalSteps formula
  // ---------------------------------------------------------------------------

  group('DebugRunnerService – totalSteps formula', () {
    test('totalSteps should equal modules.length * stepsPerModule', () {
      final registry = makeRegistry();
      final plan = DebugRunnerStepPlan(moduleCount: registry.modules.length);

      expect(plan.totalSteps, registry.modules.length * 5);
      expect(plan.totalSteps, greaterThan(0));
    });
  });
}

